/* ネイティブUIを解除 */
select {
  appearance: base-select;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 0.5rem 1rem;
  font-size: 1rem;
}

/* ドロップダウン部分 */
select::picker(select) {
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  box-shadow: 0 8px 24px rgba(0,0,0,0.12);
  padding: 0.25rem;
}

/* 各オプション */
option {
  padding: 0.5rem 1rem;
  border-radius: 4px;
}
option:hover {
  background: #eff6ff;
}
option:checked {
  background: #3b82f6;
  color: white;
}

.toast {
  opacity: 1;
  transform: translateY(0);
  transition: opacity 0.3s, transform 0.3s,
              display 0.3s allow-discrete;
}

/* DOM追加時 / display変更時の初期状態 */
@starting-style {
  .toast {
    opacity: 0;
    transform: translateY(20px);
  }
}

/* 非表示時 */
.toast.hidden {
  opacity: 0;
  transform: translateY(-20px);
  display: none;
}

/* popoverにも有効 */
[popover]:popover-open {
  opacity: 1;
  @starting-style { opacity: 0; }
}

/* ルートで有効化 */
:root {
  interpolate-size: allow-keywords;
}

/* height: auto へのトランジション */
.accordion-panel {
  height: 0;
  overflow: hidden;
  transition: height 0.3s ease;
}
.accordion-panel.open {
  height: auto; /* ← これがアニメーションする！ */
}

/* width: max-content への遷移も可能 */
.expandable {
  width: 100px;
  transition: width 0.3s;
}
.expandable:hover {
  width: max-content;
}

/* stickyヘッダーが固定された時 */
.header-wrapper {
  container-type: scroll-state;
}
@container scroll-state(stuck: top) {
  .header {
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    border-bottom: 1px solid #e5e7eb;
  }
}

/* スナップ位置にいる時 */
@container scroll-state(snapped: x) {
  .slide {
    opacity: 1;
    transform: scale(1);
  }
}

/* スクロール可能な時 */
@container scroll-state(overflowing: top) {
  .scroll-indicator-top { display: block; }
}

/* CSS if() — 提案段階の構文 */
.card {
  /* カスタムプロパティの値で分岐 */
  width: if(
    style(--size: compact): 200px;
    style(--size: full): 100%;
    else: 400px
  );

  padding: if(
    style(--dense: true): 0.5rem;
    else: 1.5rem
  );
}

/* メディア条件での分岐 */
.text {
  font-size: if(
    media(width >= 1024px): 1.25rem;
    else: 1rem
  );
}

